let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const language = input.language || 'hu';
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const aiModel = input.aiModel || 'deepseek-chat';
const customPrompt = input.customPrompt || '';
const colors = input.colors || { primary: '#6366f1', secondary: '#8b5cf6', text: '#1f2937', accent: '#f59e0b', headerBg: '#ffffff', footerBg: '#1f2937' };
const headerLogo = input.headerLogo || null;
const footerLogo = input.footerLogo || null;
const header = input.header || [];
const footer = input.footer || [];
const hero = input.hero || { enabled: true, height: 600 };

let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}
if (pages.length === 0) {
  pages = [{ name: 'Kezdőlap', slug: 'home', description: '', subpages: [] }, { name: 'Rólunk', slug: 'about', description: '', subpages: [] }, { name: 'Kapcsolat', slug: 'contact', description: '', subpages: [] }];
}

return { businessName, projectType, language, description, designStyle, aiModel, customPrompt, colors, headerLogo, footerLogo, header, hero, footer, pages };

const data = $input.all()[0].json;

const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  if (p.subpages && p.subpages.length > 0) {
    line += ' [Aloldalak: ' + p.subpages.map(sp => sp.name + '(' + sp.slug + ')' + (sp.description ? ': ' + sp.description : '')).join(', ') + ']';
  }
  return line;
}).join('\n');

const heroInfo = data.hero && data.hero.enabled
  ? `Hero: YES, height: ${data.hero.height}px. Image: ${data.hero.image ? (data.hero.image.source === 'ai' ? 'AI-generated' : 'custom uploaded') : 'none'}. Animation: ${data.hero.animation || 'none'}.`
  : 'Hero: NO.';

const headerInfo = data.header && data.header.length > 0 ? 'Header elements: ' + data.header.join(', ') : 'Header: standard (logo + nav)';
const footerInfo = data.footer && data.footer.length > 0 ? 'Footer elements: ' + data.footer.join(', ') : 'Footer: standard';

const anyAi = [data.colors.primary,data.colors.secondary,data.colors.text,data.colors.accent,data.colors.headerBg,data.colors.footerBg].filter(c => c === 'ai').length > 0;

const basePrompt = `You are a Gravity CMS expert. Generate a complete website structure.

Project: ${data.businessName}
Type: ${data.projectType}
Language: ${data.language}
Description: ${data.description}
Design: ${data.designStyle}
Colors - Primary: ${data.colors.primary}, Secondary: ${data.colors.secondary}, Text: ${data.colors.text}, Accent: ${data.colors.accent}, Header BG: ${data.colors.headerBg}, Footer BG: ${data.colors.footerBg}
${anyAi ? 'IMPORTANT: Colors marked as "ai" above must be chosen by you to perfectly match the project theme.' : ''}
${headerInfo}
${footerInfo}
${heroInfo}

Pages:
${pageList}

Output valid JSON:
{
  "pages": { "[slug]": { "title": "...", "content": { "hero": {...}, "sections": [...] }, "meta": {...}, "subpages": {...} } },
  "config": { "system": {...}, "theme": { "colors": {...} }, "header": {...}, "footer": {...}, "plugins": [...] },
  "admin_structure": {...}
}

Use provided descriptions. Professional, SEO-optimized content.`;

const prompt = data.customPrompt ? basePrompt + '\n\nADDITIONAL USER INSTRUCTIONS: ' + data.customPrompt : basePrompt;

return { prompt, aiModel: data.aiModel };

const fs = require('fs');
const path = require('path');
const response = $input.all()[0].json;
let content;
try {
  const aiResponse = response.choices[0].message.content;
  let jsonStr = aiResponse;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  content = JSON.parse(jsonStr);
} catch (e) {
  content = { error: "Failed to parse AI response", raw: response.choices[0].message.content };
}

// ----- Fájlba mentés (JSON) -----
const outputDir = '/home/node/output';
const bizName = ($items('Bemenet feldolgozása (Code)').$node['Bemenet feldolgozása (Code)'].json || {}).businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const filename = path.join(outputDir, safeName + '_' + ts + '.json');
try {
  if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(filename, JSON.stringify(content, null, 2), 'utf8');
} catch (err) {}

// ----- Gravity CMS deploy (.md fájlok generálása) -----
if (content.pages) {
  const gravPagesDir = '/home/node/gravity-pages';
  try {
    if (!fs.existsSync(gravPagesDir)) fs.mkdirSync(gravPagesDir, { recursive: true });

    Object.keys(content.pages).forEach(slug => {
      const page = content.pages[slug];
      const pageDir = path.join(gravPagesDir, '01.' + safeName);
      if (!fs.existsSync(pageDir)) fs.mkdirSync(pageDir, { recursive: true });

      const mdName = slug === 'home' ? 'default.md' : slug + '.md';
      const mdPath = path.join(pageDir, mdName);

      let mdContent = '---\n';
      mdContent += 'title: "' + (page.title || slug) + '"\n';
      if (page.meta) {
        mdContent += 'metadata:\n';
        mdContent += '  description: "' + (page.meta.description || '') + '"\n';
      }
      mdContent += 'visible: true\n';
      mdContent += '---\n\n';
      if (page.content && page.content.hero) {
        const hero = page.content.hero;
        mdContent += '# ' + (hero.title || '') + '\n\n';
        if (hero.subtitle) mdContent += hero.subtitle + '\n\n';
      }
      if (page.content && page.content.sections) {
        page.content.sections.forEach(sec => {
          mdContent += '## ' + (sec.title || '') + '\n\n';
          if (sec.content) mdContent += sec.content + '\n\n';
        });
      }

      fs.writeFileSync(mdPath, mdContent, 'utf8');
    });
  } catch (err) {}
}

return { generated: content, saved_to: filename, gravity_deployed: content.pages ? true : false, timestamp: new Date().toISOString(), model: response.model || 'deepseek-chat', usage: response.usage || {} };
